var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。`,ENG:`that you'll be with her, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called her to your office. She said she'd be here soon.`,TWN:`做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`YOONA_STREGA_NULL_NULL`,text:{KOREA:`사장님이...... 날 선택했다고? 나야 좋지만, 왜, 왜? 어째서?`,JPN:`社長が……私を選んでくれたの？
嬉しいけど……何で？　どうして？`,ENG:`You've chosen me? I'm glad, but why? Why me?`,TWN:`老闆……選擇了我？我是很開心啦，但是……為什麼，為什麼？為什麼是我？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YOONA_STREGA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`YOONA_STREGA_NULL_NULL`,text:{KOREA:`내가 잠재력이 있으니 정식마녀가 될 수 있도록 도와줄 거라고? 진심이야?`,JPN:`私の潜在能力を開花させて、
一人前の魔女になれる手助けをしてくれるって？　本気なの？`,ENG:`You want to help me because I have the makings of a good witch? Are you serious?`,TWN:`你說我有潛力，會幫助我成為正式的魔女？你是認真的嗎？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YOONA_STREGA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`YOONA_STREGA_NULL_NULL`,text:{KOREA:`우후후, 사장님도 참. 인재를 알아보다니. 역시 안목이 좋다니깐?`,JPN:`へへ、社長ったら。このユナ・スプリングフィールドという逸材に目をつけるなんて、さすがね。`,ENG:`Hah hah. I knew you had an eye for genius.`,TWN:`呵呵呵，老闆也真是的。居然能發現我是個人才，眼光果然不錯嘛？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YOONA_STREGA_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`YOONA_STREGA_NULL_NULL`,text:{KOREA:`자, 계약서까지 썼으니까. 가르치기 힘들다고 먼저 포기하기 없기다?!`,JPN:`ほら、契約書も書いたよ。途中で投げないで、ちゃんと最後まで導いてよね！？`,ENG:`There, I signed it. You'd better not give up on me because I'm hard to teach. Promise?`,TWN:`那麼，既然契約也簽了，老闆可不能因為我太難教，就先放棄我喔？！`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YOONA_STREGA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};